# Measuring alignment tax: compare SFT and RLHF models on capability benchmarks
from lm_eval import evaluator

def measure_alignment_tax(sft_model_path: str, rlhf_model_path: str):
    benchmarks = ["mmlu", "gsm8k", "humaneval", "triviaqa"]
    results = {}
    for model_path, label in [(sft_model_path, "sft"), (rlhf_model_path, "rlhf")]:
        scores = evaluator.simple_evaluate(
            model="hf",
            model_args=f"pretrained={model_path}",
            tasks=benchmarks,
            num_fewshot=5,
        )
        results[label] = {task: scores["results"][task]["acc,none"] for task in benchmarks}

    print("Alignment tax (RLHF - SFT delta):")
    for task in benchmarks:
        delta = results["rlhf"][task] - results["sft"][task]
        sign = "+" if delta >= 0 else ""
        print(f"  {task}: {sign}{delta*100:.1f}%")
    return results
